def gen(rng, size):
    n = max(2, size)
    minK, maxK = 3, 8
    nums = []
    for _ in range(n):
        r = rng.random()
        if r < 0.2:
            nums.append(rng.choice([1, 2, 9, 10]))
        else:
            nums.append(rng.randint(minK, maxK))
    return [nums, minK, maxK]

