class Solution:
    def countSubarrays(self, nums, minK, maxK):
        n = len(nums)
        count = 0
        for i in range(n):
            mn = nums[i]
            mx = nums[i]
            for j in range(i, n):
                if nums[j] < mn:
                    mn = nums[j]
                if nums[j] > mx:
                    mx = nums[j]
                if mn == minK and mx == maxK:
                    count += 1
        return count

