class Solution:
    def countSubarrays(self, nums, minK, maxK):
        ans = 0
        last_bad = -1
        last_min = -1
        last_max = -1
        for i, v in enumerate(nums):
            if v < minK or v > maxK:
                last_bad = i
            if v == minK:
                last_min = i
            if v == maxK:
                last_max = i
            good = min(last_min, last_max) - last_bad
            if good > 0:
                ans += good
        return ans

