var countSubarrays = function(nums, minK, maxK) {
    let ans = 0, lastBad = -1, lastMin = -1, lastMax = -1;
    for (let i = 0; i < nums.length; i++) {
        const v = nums[i];
        if (v < minK || v > maxK) lastBad = i;
        if (v === minK) lastMin = i;
        if (v === maxK) lastMax = i;
        const good = Math.min(lastMin, lastMax) - lastBad;
        if (good > 0) ans += good;
    }
    return ans;
};
